import{_ as l,o,c as a,ae as i}from"./chunks/framework.C7FLYIpo.js";const m=JSON.parse('{"title":"CLI 설정 참조","description":"CLI 설정 흐름, 인증/모델 설정, 출력 및 내부 구조에 대한 완전한 참조","frontmatter":{"title":"CLI 설정 참조","description":"CLI 설정 흐름, 인증/모델 설정, 출력 및 내부 구조에 대한 완전한 참조"},"headers":[],"relativePath":"start/wizard-cli-reference.md","filePath":"start/wizard-cli-reference.md","lastUpdated":null}'),c={name:"start/wizard-cli-reference.md"};function s(t,e,d,n,r,p){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="cli-설정-참조" tabindex="-1">CLI 설정 참조 <a class="header-anchor" href="#cli-설정-참조" aria-label="Permalink to &quot;CLI 설정 참조&quot;">​</a></h1><p>이 페이지는 <code>openclaw onboard</code>의 전체 참조입니다. 간단한 가이드는 <a href="/openclaw-docs-ko/start/wizard">온보딩 (CLI)</a>를 참조하십시오.</p><h2 id="마법사가-수행하는-작업" tabindex="-1">마법사가 수행하는 작업 <a class="header-anchor" href="#마법사가-수행하는-작업" aria-label="Permalink to &quot;마법사가 수행하는 작업&quot;">​</a></h2><p>로컬 모드 (기본값)는 다음을 안내합니다:</p><ul><li>모델 및 인증 설정 (OpenAI Code 구독 OAuth, Anthropic Claude CLI 또는 API 키, MiniMax, GLM, Ollama, Moonshot, StepFun 및 AI Gateway 옵션 포함)</li><li>워크스페이스 위치 및 부트스트랩 파일</li><li>Gateway 설정 (포트, 바인드, 인증, tailscale)</li><li>채널 및 프로바이더 (Telegram, WhatsApp, Discord, Google Chat, Mattermost, Signal, BlueBubbles 및 기타 번들 채널 플러그인)</li><li>데몬 설치 (LaunchAgent, systemd 사용자 유닛 또는 Startup 폴더 대체 기능이 있는 네이티브 Windows 예약 작업)</li><li>헬스 체크</li><li>스킬 설정</li></ul><p>원격 모드는 이 머신이 다른 곳의 게이트웨이에 연결하도록 구성합니다. 원격 호스트에서는 아무것도 설치하거나 수정하지 않습니다.</p><h2 id="로컬-흐름-세부-정보" tabindex="-1">로컬 흐름 세부 정보 <a class="header-anchor" href="#로컬-흐름-세부-정보" aria-label="Permalink to &quot;로컬 흐름 세부 정보&quot;">​</a></h2><ol><li><p><strong>기존 구성 감지</strong></p><ul><li><code>~/.openclaw/openclaw.json</code>이 존재하면 유지, 수정 또는 재설정을 선택합니다. <ul><li>마법사를 다시 실행해도 재설정을 명시적으로 선택하지 않는 한 (또는 <code>--reset</code>을 전달하지 않는 한) 아무것도 지우지 않습니다.</li><li>CLI <code>--reset</code>은 기본값으로 <code>config+creds+sessions</code>입니다; 워크스페이스도 제거하려면 <code>--reset-scope full</code>을 사용하십시오.</li><li>구성이 잘못되었거나 레거시 키가 포함된 경우, 마법사는 계속하기 전에 <code>openclaw doctor</code>를 실행하도록 요청합니다.</li><li>재설정은 <code>trash</code>를 사용하고 다음 범위를 제공합니다: <ul><li>구성만</li><li>구성 + 자격 증명 + 세션</li><li>전체 재설정 (워크스페이스도 제거)</li></ul></li></ul></li></ul></li><li><p><strong>모델 및 인증</strong></p></li></ol><ul><li>전체 옵션 매트릭스는 <a href="#auth-and-model-options">인증 및 모델 옵션</a>에 있습니다.</li></ul><ol start="3"><li><strong>워크스페이스</strong></li></ol><ul><li>기본값 <code>~/.openclaw/workspace</code> (구성 가능). <ul><li>최초 실행 부트스트랩 의식에 필요한 워크스페이스 파일을 초기화합니다.</li><li>워크스페이스 레이아웃: <a href="/openclaw-docs-ko/concepts/agent-workspace">에이전트 워크스페이스</a>.</li></ul></li></ul><ol start="4"><li><strong>Gateway</strong></li></ol><ul><li>포트, 바인드, 인증 모드 및 tailscale 노출에 대한 프롬프트. <ul><li>권장: 로컬 WS 클라이언트가 인증해야 하도록 루프백에서도 토큰 인증을 활성화한 상태로 유지하십시오.</li><li>토큰 모드에서, 대화형 설정은 다음을 제공합니다: <ul><li><strong>평문 토큰 생성/저장</strong> (기본값)</li><li><strong>SecretRef 사용</strong> (옵트인)</li></ul></li><li>비밀번호 모드에서, 대화형 설정도 평문 또는 SecretRef 저장을 지원합니다.</li><li>비대화형 토큰 SecretRef 경로: <code>--gateway-token-ref-env &amp;lt;ENV_VAR&amp;gt;</code>. <ul><li>온보딩 프로세스 환경에서 비어 있지 않은 환경 변수가 필요합니다.</li><li><code>--gateway-token</code>과 결합할 수 없습니다.</li></ul></li><li>모든 로컬 프로세스를 완전히 신뢰하는 경우에만 인증을 비활성화하십시오.</li><li>루프백이 아닌 바인드에는 여전히 인증이 필요합니다.</li></ul></li></ul><ol start="5"><li><strong>채널</strong></li></ol><ul><li><a href="/openclaw-docs-ko/channels/whatsapp">WhatsApp</a>: 선택적 QR 로그인 <ul><li><a href="/openclaw-docs-ko/channels/telegram">Telegram</a>: 봇 토큰</li><li><a href="/openclaw-docs-ko/channels/discord">Discord</a>: 봇 토큰</li><li><a href="/openclaw-docs-ko/channels/googlechat">Google Chat</a>: 서비스 계정 JSON + 웹훅 대상</li><li><a href="/openclaw-docs-ko/channels/mattermost">Mattermost</a>: 봇 토큰 + 기본 URL</li><li><a href="/openclaw-docs-ko/channels/signal">Signal</a>: 선택적 <code>signal-cli</code> 설치 + 계정 구성</li><li><a href="/openclaw-docs-ko/channels/bluebubbles">BlueBubbles</a>: iMessage에 권장; 서버 URL + 비밀번호 + 웹훅</li><li><a href="/openclaw-docs-ko/channels/imessage">iMessage</a>: 레거시 <code>imsg</code> CLI 경로 + DB 접근</li><li>DM 보안: 기본값은 페어링입니다. 첫 번째 DM은 코드를 보냅니다; <code>openclaw pairing approve &amp;lt;channel&amp;gt; &lt;code&gt;</code>를 통해 승인하거나 허용 목록을 사용하십시오.</li></ul></li></ul><ol start="6"><li><strong>데몬 설치</strong></li></ol><ul><li>macOS: LaunchAgent - 로그인된 사용자 세션이 필요합니다; 헤드리스의 경우 맞춤 LaunchDaemon을 사용하십시오 (제공되지 않음). <ul><li>WSL2를 통한 Linux 및 Windows: systemd 사용자 유닛 <ul><li>마법사는 로그아웃 후에도 게이트웨이가 계속 실행되도록 <code>loginctl enable-linger &amp;lt;user&amp;gt;</code>를 시도합니다.</li><li>sudo를 요청할 수 있습니다 (<code>/var/lib/systemd/linger</code>를 작성합니다); 먼저 sudo 없이 시도합니다.</li></ul></li><li>네이티브 Windows: 예약 작업 우선 <ul><li>작업 생성이 거부되면 OpenClaw는 사용자별 Startup 폴더 로그인 항목으로 대체하고 즉시 게이트웨이를 시작합니다.</li><li>더 나은 감독 상태를 제공하므로 예약 작업이 선호됩니다.</li></ul></li><li>런타임 선택: Node (권장; WhatsApp 및 Telegram에 필요). Bun은 권장하지 않습니다.</li></ul></li></ul><ol start="7"><li><strong>헬스 체크</strong></li></ol><ul><li>게이트웨이를 시작하고 (필요한 경우) <code>openclaw health</code>를 실행합니다. <ul><li><code>openclaw status --deep</code>은 채널 프로브가 지원될 때 채널 프로브를 포함한 라이브 게이트웨이 헬스 프로브를 상태 출력에 추가합니다.</li></ul></li></ul><ol start="8"><li><strong>스킬</strong></li></ol><ul><li>사용 가능한 스킬을 읽고 요구 사항을 확인합니다. <ul><li>노드 관리자 선택: npm, pnpm 또는 bun.</li><li>선택적 의존성을 설치합니다 (일부는 macOS에서 Homebrew를 사용합니다).</li></ul></li></ul><ol start="9"><li><strong>완료</strong></li></ol><ul><li>요약 및 iOS, Android 및 macOS 앱 옵션을 포함한 다음 단계.</li></ul><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>GUI가 감지되지 않으면, 마법사는 브라우저를 여는 대신 Control UI에 대한 SSH 포트 포워드 지침을 출력합니다. Control UI 에셋이 없으면 마법사가 빌드를 시도합니다; 대체는 <code>pnpm ui:build</code>입니다 (UI 의존성 자동 설치).</p></div><h2 id="원격-모드-세부-정보" tabindex="-1">원격 모드 세부 정보 <a class="header-anchor" href="#원격-모드-세부-정보" aria-label="Permalink to &quot;원격 모드 세부 정보&quot;">​</a></h2><p>원격 모드는 이 머신이 다른 곳의 게이트웨이에 연결하도록 구성합니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>원격 모드는 원격 호스트에서 아무것도 설치하거나 수정하지 않습니다.</p></div><p>설정 항목:</p><ul><li>원격 게이트웨이 URL (<code>ws://...</code>)</li><li>원격 게이트웨이 인증이 필요한 경우 토큰 (권장)</li></ul><div class="info custom-block"><p class="custom-block-title">NOTE</p><ul><li>게이트웨이가 루프백 전용인 경우 SSH 터널링 또는 tailnet을 사용하십시오.</li><li>디스커버리 힌트: <ul><li>macOS: Bonjour (<code>dns-sd</code>)</li><li>Linux: Avahi (<code>avahi-browse</code>)</li></ul></li></ul></div><h2 id="인증-및-모델-옵션" tabindex="-1">인증 및 모델 옵션 <a class="header-anchor" href="#인증-및-모델-옵션" aria-label="Permalink to &quot;인증 및 모델 옵션&quot;">​</a></h2><details class="details custom-block"><summary>Anthropic API 키</summary><p><code>ANTHROPIC_API_KEY</code>가 있으면 사용하거나 키를 요청한 후 데몬 사용을 위해 저장합니다.</p></details><details class="details custom-block"><summary>OpenAI Code 구독 (Codex CLI 재사용)</summary><p><code>~/.codex/auth.json</code>이 존재하면 마법사가 재사용할 수 있습니다. 재사용된 Codex CLI 자격 증명은 Codex CLI에서 관리됩니다; 만료 시 OpenClaw는 해당 소스를 먼저 다시 읽고, 프로바이더가 이를 새로 고침할 수 있을 때는 소유권을 가져가는 대신 새로 고침된 자격 증명을 Codex 저장소에 다시 씁니다.</p></details><details class="details custom-block"><summary>OpenAI Code 구독 (OAuth)</summary><p>브라우저 흐름; <code>code#state</code>를 붙여넣으십시오.</p><pre><code>모델이 설정되지 않았거나 `openai/*`인 경우 `agents.defaults.model`을 `openai-codex/gpt-5.4`로 설정합니다.\n</code></pre></details><details class="details custom-block"><summary>OpenAI API 키</summary><p><code>OPENAI_API_KEY</code>가 있으면 사용하거나 키를 요청한 후 인증 프로파일에 자격 증명을 저장합니다.</p><pre><code>모델이 설정되지 않았거나 `openai/*` 또는 `openai-codex/*`인 경우 `agents.defaults.model`을 `openai/gpt-5.4`로 설정합니다.\n</code></pre></details><details class="details custom-block"><summary>xAI (Grok) API 키</summary><p><code>XAI_API_KEY</code>를 요청하고 xAI를 모델 프로바이더로 구성합니다.</p></details><details class="details custom-block"><summary>OpenCode</summary><p><code>OPENCODE_API_KEY</code> (또는 <code>OPENCODE_ZEN_API_KEY</code>)를 요청하고 Zen 또는 Go 카탈로그를 선택합니다. 설정 URL: <a href="https://opencode.ai/auth" target="_blank" rel="noreferrer">opencode.ai/auth</a>.</p></details><details class="details custom-block"><summary>API 키 (일반)</summary><p>키를 저장합니다.</p></details><details class="details custom-block"><summary>Vercel AI Gateway</summary><p><code>AI_GATEWAY_API_KEY</code>를 요청합니다. 자세한 내용: <a href="/openclaw-docs-ko/providers/vercel-ai-gateway">Vercel AI Gateway</a>.</p></details><details class="details custom-block"><summary>Cloudflare AI Gateway</summary><p>계정 ID, 게이트웨이 ID 및 <code>CLOUDFLARE_AI_GATEWAY_API_KEY</code>를 요청합니다. 자세한 내용: <a href="/openclaw-docs-ko/providers/cloudflare-ai-gateway">Cloudflare AI Gateway</a>.</p></details><details class="details custom-block"><summary>MiniMax</summary><p>구성이 자동으로 작성됩니다. 호스팅된 기본값은 <code>MiniMax-M2.7</code>입니다; API 키 설정은 <code>minimax/...</code>를 사용하고, OAuth 설정은 <code>minimax-portal/...</code>를 사용합니다. 자세한 내용: <a href="/openclaw-docs-ko/providers/minimax">MiniMax</a>.</p></details><details class="details custom-block"><summary>StepFun</summary><p>중국 또는 글로벌 엔드포인트의 StepFun 표준 또는 Step Plan에 대해 구성이 자동으로 작성됩니다. 표준에는 현재 <code>step-3.5-flash</code>가 포함되며, Step Plan에도 <code>step-3.5-flash-2603</code>이 포함됩니다. 자세한 내용: <a href="/openclaw-docs-ko/providers/stepfun">StepFun</a>.</p></details><details class="details custom-block"><summary>Synthetic (Anthropic 호환)</summary><p><code>SYNTHETIC_API_KEY</code>를 요청합니다. 자세한 내용: <a href="/openclaw-docs-ko/providers/synthetic">Synthetic</a>.</p></details><details class="details custom-block"><summary>Ollama (클라우드 및 로컬 오픈 모델)</summary><p>기본 URL (기본값 <code>http://127.0.0.1:11434</code>)을 요청한 후 클라우드 + 로컬 또는 로컬 모드를 제공합니다. 사용 가능한 모델을 검색하고 기본값을 제안합니다. 자세한 내용: <a href="/openclaw-docs-ko/providers/ollama">Ollama</a>.</p></details><details class="details custom-block"><summary>Moonshot 및 Kimi Coding</summary><p>Moonshot (Kimi K2) 및 Kimi Coding 구성이 자동으로 작성됩니다. 자세한 내용: <a href="/openclaw-docs-ko/providers/moonshot">Moonshot AI (Kimi + Kimi Coding)</a>.</p></details><details class="details custom-block"><summary>맞춤형 프로바이더</summary><p>OpenAI 호환 및 Anthropic 호환 엔드포인트와 함께 작동합니다.</p><pre><code>대화형 온보딩은 다른 프로바이더 API 키 흐름과 동일한 API 키 저장 선택을 지원합니다:\n- **지금 API 키 붙여넣기** (평문)\n- **비밀 참조 사용** (환경 변수 참조 또는 구성된 프로바이더 참조, 사전 검증 포함)\n\n비대화형 플래그:\n- `--auth-choice custom-api-key`\n- `--custom-base-url`\n- `--custom-model-id`\n- `--custom-api-key` (선택 사항; `CUSTOM_API_KEY`로 대체됨)\n- `--custom-provider-id` (선택 사항)\n- `--custom-compatibility &amp;lt;openai|anthropic&amp;gt;` (선택 사항; 기본값 `openai`)\n</code></pre></details><details class="details custom-block"><summary>건너뛰기</summary><p>인증을 구성되지 않은 상태로 둡니다.</p></details><p>모델 동작:</p><ul><li>감지된 옵션에서 기본 모델을 선택하거나 프로바이더 및 모델을 수동으로 입력합니다.</li><li>온보딩이 프로바이더 인증 선택에서 시작되면, 모델 선택기는 해당 프로바이더를 자동으로 선호합니다. Volcengine 및 BytePlus의 경우, 동일한 선호도가 코딩 플랜 변형 (<code>volcengine-plan/*</code>, <code>byteplus-plan/*</code>)에도 적용됩니다.</li><li>선호 프로바이더 필터가 비어 있으면, 선택기는 모델이 없는 상태로 표시하는 대신 전체 카탈로그로 대체됩니다.</li><li>마법사는 모델 확인을 실행하고 구성된 모델이 알 수 없거나 인증이 없는 경우 경고합니다.</li></ul><p>자격 증명 및 프로파일 경로:</p><ul><li>인증 프로파일 (API 키 + OAuth): <code>~/.openclaw/agents/&amp;lt;agentId&amp;gt;/agent/auth-profiles.json</code></li><li>레거시 OAuth 가져오기: <code>~/.openclaw/credentials/oauth.json</code></li></ul><p>자격 증명 저장 모드:</p><ul><li>기본 온보딩 동작은 API 키를 인증 프로파일의 평문 값으로 유지합니다.</li><li><code>--secret-input-mode ref</code>는 평문 키 저장 대신 참조 모드를 활성화합니다. 대화형 설정에서 다음 중 하나를 선택할 수 있습니다: <ul><li>환경 변수 참조 (예: <code>keyRef: { source: &quot;env&quot;, provider: &quot;default&quot;, id: &quot;OPENAI_API_KEY&quot; }</code>)</li><li>구성된 프로바이더 참조 (<code>file</code> 또는 <code>exec</code>) (프로바이더 별칭 + id 포함)</li></ul></li><li>대화형 참조 모드는 저장 전 빠른 사전 검증을 실행합니다. <ul><li>환경 변수 참조: 현재 온보딩 환경에서 변수 이름 + 비어 있지 않은 값을 검증합니다.</li><li>프로바이더 참조: 프로바이더 구성을 검증하고 요청된 id를 확인합니다.</li><li>사전 검증이 실패하면 온보딩이 오류를 표시하고 재시도할 수 있습니다.</li></ul></li><li>비대화형 모드에서 <code>--secret-input-mode ref</code>는 환경 변수 기반만 지원합니다. <ul><li>온보딩 프로세스 환경에서 프로바이더 환경 변수를 설정하십시오.</li><li>인라인 키 플래그 (예: <code>--openai-api-key</code>)는 해당 환경 변수가 설정되어 있어야 합니다; 그렇지 않으면 온보딩이 빠르게 실패합니다.</li><li>맞춤형 프로바이더의 경우, 비대화형 <code>ref</code> 모드는 <code>models.providers.&amp;lt;id&amp;gt;.apiKey</code>를 <code>{ source: &quot;env&quot;, provider: &quot;default&quot;, id: &quot;CUSTOM_API_KEY&quot; }</code>로 저장합니다.</li><li>해당 맞춤형 프로바이더 경우, <code>--custom-api-key</code>는 <code>CUSTOM_API_KEY</code>가 설정되어 있어야 합니다; 그렇지 않으면 온보딩이 빠르게 실패합니다.</li></ul></li><li>Gateway 인증 자격 증명은 대화형 설정에서 평문 및 SecretRef 선택을 지원합니다: <ul><li>토큰 모드: <strong>평문 토큰 생성/저장</strong> (기본값) 또는 <strong>SecretRef 사용</strong>.</li><li>비밀번호 모드: 평문 또는 SecretRef.</li></ul></li><li>비대화형 토큰 SecretRef 경로: <code>--gateway-token-ref-env &amp;lt;ENV_VAR&amp;gt;</code>.</li><li>기존 평문 설정은 변경 없이 계속 작동합니다.</li></ul><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>헤드리스 및 서버 팁: 브라우저가 있는 머신에서 OAuth를 완료한 후, 해당 에이전트의 <code>auth-profiles.json</code> (예: <code>~/.openclaw/agents/&amp;lt;agentId&amp;gt;/agent/auth-profiles.json</code> 또는 일치하는 <code>$OPENCLAW_STATE_DIR/...</code> 경로)을 게이트웨이 호스트로 복사하십시오. <code>credentials/oauth.json</code>은 레거시 가져오기 소스일 뿐입니다.</p></div><h2 id="출력-및-내부-구조" tabindex="-1">출력 및 내부 구조 <a class="header-anchor" href="#출력-및-내부-구조" aria-label="Permalink to &quot;출력 및 내부 구조&quot;">​</a></h2><p><code>~/.openclaw/openclaw.json</code>의 일반적인 필드:</p><ul><li><code>agents.defaults.workspace</code></li><li><code>agents.defaults.model</code> / <code>models.providers</code> (Minimax 선택 시)</li><li><code>tools.profile</code> (로컬 온보딩은 설정되지 않은 경우 기본값으로 <code>&quot;coding&quot;</code>을 사용합니다; 기존 명시적 값은 보존됩니다)</li><li><code>gateway.*</code> (모드, 바인드, 인증, tailscale)</li><li><code>session.dmScope</code> (로컬 온보딩은 설정되지 않은 경우 이를 <code>per-channel-peer</code>로 기본 설정합니다; 기존 명시적 값은 보존됩니다)</li><li><code>channels.telegram.botToken</code>, <code>channels.discord.token</code>, <code>channels.matrix.*</code>, <code>channels.signal.*</code>, <code>channels.imessage.*</code></li><li>채널 허용 목록 (Slack, Discord, Matrix, Microsoft Teams) — 프롬프트에서 옵트인할 때 (이름이 가능한 경우 ID로 확인됩니다)</li><li><code>skills.install.nodeManager</code><ul><li><code>setup --node-manager</code> 플래그는 <code>npm</code>, <code>pnpm</code> 또는 <code>bun</code>을 허용합니다.</li><li>수동 구성은 나중에 <code>skills.install.nodeManager: &quot;yarn&quot;</code>을 설정할 수 있습니다.</li></ul></li><li><code>wizard.lastRunAt</code></li><li><code>wizard.lastRunVersion</code></li><li><code>wizard.lastRunCommit</code></li><li><code>wizard.lastRunCommand</code></li><li><code>wizard.lastRunMode</code></li></ul><p><code>openclaw agents add</code>는 <code>agents.list[]</code> 및 선택적 <code>bindings</code>를 작성합니다.</p><p>WhatsApp 자격 증명은 <code>~/.openclaw/credentials/whatsapp/&amp;lt;accountId&amp;gt;/</code> 아래에 있습니다. 세션은 <code>~/.openclaw/agents/&amp;lt;agentId&amp;gt;/sessions/</code> 아래에 저장됩니다.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>일부 채널은 플러그인으로 제공됩니다. 설정 중 선택하면 마법사가 채널 구성 전에 플러그인을 설치하도록 요청합니다 (npm 또는 로컬 경로).</p></div><p>Gateway 마법사 RPC:</p><ul><li><code>wizard.start</code></li><li><code>wizard.next</code></li><li><code>wizard.cancel</code></li><li><code>wizard.status</code></li></ul><p>클라이언트 (macOS 앱 및 Control UI)는 온보딩 로직을 다시 구현하지 않고도 단계를 렌더링할 수 있습니다.</p><p>Signal 설정 동작:</p><ul><li>적절한 릴리스 에셋을 다운로드합니다</li><li><code>~/.openclaw/tools/signal-cli/&amp;lt;version&amp;gt;/</code> 아래에 저장합니다</li><li>구성에 <code>channels.signal.cliPath</code>를 작성합니다</li><li>JVM 빌드에는 Java 21이 필요합니다</li><li>가능한 경우 네이티브 빌드를 사용합니다</li><li>Windows는 WSL2를 사용하고 WSL 내에서 Linux signal-cli 흐름을 따릅니다</li></ul><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li>온보딩 허브: <a href="/openclaw-docs-ko/start/wizard">온보딩 (CLI)</a></li><li>자동화 및 스크립트: <a href="/openclaw-docs-ko/start/wizard-cli-automation">CLI 자동화</a></li><li>명령 참조: <a href="/openclaw-docs-ko/cli/onboard"><code>openclaw onboard</code></a></li></ul>',67)])])}const h=l(c,[["render",s]]);export{m as __pageData,h as default};
